// Suprimir warnings de execu├з├╡es perdidas do node-cron
const originalWarn = console.warn;
console.warn = (...args) => {
  if (args[0] && args[0].includes && args[0].includes('missed execution')) return;
  originalWarn.apply(console, args);
};

// Fun├з├гo auxiliar de formata├з├гo de texto (usada em boas-vindas e sa├нda)
function formatMessageText(template, replacements) {
  let text = template;
  for (const [key, value] of Object.entries(replacements)) {
    text = text.replaceAll(key, value);
  }
  return text;
}

/**
 * Fun├з├гo para lidar com eventos de participantes do grupo (Boas-vindas)
 * Adicionada para corrigir o problema do bot n├гo enviar bem-vindo.
 */
export const handleGroupParticipantsUpdate = async (nazu, { id, participants, action }) => {
    // Log incondicional para diagn├│stico no terminal do usu├бrio
    console.log(`\x1b[36m[PARTICIPANTS UPDATE]\x1b[0m Evento: \x1b[33m${action}\x1b[0m | Grupo: \x1b[32m${id}\x1b[0m | Membros: ${participants.length}`);
    
    try {
        // 1. Tentar obter metadata com retry ou fallback
        let groupMetadata = await nazu.groupMetadata(id).catch(() => null);
        
        if (!groupMetadata) {
            console.log(`\x1b[31m[PARTICIPANTS UPDATE]\x1b[0m Falha ao obter metadata para o grupo ${id}. Tentando prosseguir com dados b├бsicos.`);
            groupMetadata = { id, subject: 'Grupo', participants: [] };
        }
        
        // 2. Carregar configura├з├╡es do grupo
        const groupSettings = await loadGroupSettings(id);
        
        // 3. L├│gica de ADICIONAR (Boas-vindas)
        if (action === 'add') {
            // Suporte a m├║ltiplas varia├з├╡es de chave usadas no JSON do grupo
            const isBv1 = !!(groupSettings.bemvindo || groupSettings.boasvindas || groupSettings.welcome?.enabled);
            const isBv2 = !!(groupSettings.bemvindo2 || groupSettings.boasvindas2);

            // Log de diagn├│stico para facilitar depura├з├гo
            console.log(`\x1b[34m[PARTICIPANTS UPDATE]\x1b[0m Chaves do grupo: bemvindo=${groupSettings.bemvindo}, bemvindo2=${groupSettings.bemvindo2}, welcome=${JSON.stringify(groupSettings.welcome)}`);

            if (isBv1 || isBv2) {
                console.log(`\x1b[34m[PARTICIPANTS UPDATE]\x1b[0m Preparando Boas-vindas (Modo: ${isBv2 ? 'BV2' : 'BV1'})`);
                
                const settings = {
                    text: isBv2 ? (groupSettings.textbv2 || groupSettings.boasvindas2) : (groupSettings.textbv || groupSettings.boasvindas),
                    photoType: isBv2 ? 'none' : (groupSettings.welcome?.photoType || 'api'),
                    photo: isBv2 ? false : (groupSettings.welcome?.photo !== false),
                    image: isBv2 ? null : groupSettings.welcome?.image
                };

                const message = await createGroupMessage(
                    nazu,
                    groupMetadata,
                    participants,
                    settings,
                    true
                );

                await nazu.sendMessage(id, message);
                console.log(`\x1b[32m[PARTICIPANTS UPDATE]\x1b[0m Mensagem de boas-vindas enviada.`);
            } else {
                console.log(`\x1b[33m[PARTICIPANTS UPDATE]\x1b[0m Boas-vindas est├гo DESATIVADAS para este grupo.`);
            }
        } 
        
        // 4. L├│gica de REMOVER (Sa├нda)
        else if (action === 'remove') {
            if (groupSettings.exit?.enabled) {
                console.log(`\x1b[34m[PARTICIPANTS UPDATE]\x1b[0m Preparando mensagem de Sa├нda`);
                
                const exitText = groupSettings.exit?.text ||
                    "тХнтФБтФБтФБтК▒ ЁЯСЛ *AT├Й LOGO!* ЁЯСЛ тК▒тФБтФБтФБтХо\nтФВ\nтФВ ЁЯСд #numerodele#\nтФВ\nтФВ ЁЯЪк Saiu do grupo\nтФВ *#nomedogp#*\nтФВ\nтХ░тФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтХп\n\nЁЯТл *At├й a pr├│xima!* ЁЯТл";

                const participantIds = participants.map(p => typeof p === 'string' ? p : (p.id || p.jid || p.toString()));

                const replacements = {
                    '#numerodele#': participantIds.map(p => `@${p.split('@')[0]}`).join(', '),
                    '#nomedogp#': groupMetadata.subject,
                    '#membros#': groupMetadata.participants.length,
                };

                const text = formatMessageText(exitText, replacements);
                const mentions = participantIds;

                const exitMessage = { text, mentions };

                if (groupSettings.exit?.image) {
                    exitMessage.image = { url: groupSettings.exit.image };
                    exitMessage.caption = text;
                    delete exitMessage.text;
                }

                await nazu.sendMessage(id, exitMessage);
                console.log(`\x1b[32m[PARTICIPANTS UPDATE]\x1b[0m Mensagem de sa├нda enviada.`);
            }
        }
    } catch (e) {
        console.error(`\x1b[31m[ERRO PARTICIPANTS UPDATE]:\x1b[0m`, e);
    }
};

dotenv.config();

