const writeJsonFile = (filePath, data) => {
  try {
    // Valida├з├гo de entrada
    if (data === undefined || data === null) {
      console.error(`тЭМ writeJsonFile: Tentativa de salvar dados nulos em ${filePath}`);
      return false;
    }

    // Testa se dados s├гo serializ├бveis
    let jsonString;
    try {
      jsonString = JSON.stringify(data, null, 2);
    } catch (stringifyError) {
      console.error(`тЭМ writeJsonFile: Dados n├гo serializ├бveis para ${filePath}:`, stringifyError.message);
      return false;
    }

    // Valida JSON gerado
    try {
      JSON.parse(jsonString);
    } catch (validateError) {
      console.error(`тЭМ writeJsonFile: JSON inv├бlido gerado para ${filePath}`);
      return false;
    }

    ensureDirectoryExists(pathz.dirname(filePath));

    // Escreve em arquivo tempor├бrio primeiro (opera├з├гo at├┤mica)
    const tempPath = filePath + '.tmp';
    fs.writeFileSync(tempPath, jsonString, 'utf-8');

    // Verifica integridade do arquivo tempor├бrio
    try {
      const writtenContent = fs.readFileSync(tempPath, 'utf-8');
      JSON.parse(writtenContent);
    } catch (verifyError) {
      console.error(`тЭМ writeJsonFile: Verifica├з├гo falhou para ${filePath}`);
      try { fs.unlinkSync(tempPath); } catch (e) { }
      return false;
    }

    // Move arquivo tempor├бrio para destino (at├┤mico)
    fs.renameSync(tempPath, filePath);
    return true;
  } catch (error) {
    console.error(`тЭМ Erro ao escrever JSON em ${filePath}:`, error.message);
    // Tenta limpar arquivo tempor├бrio
    try {
      const tempPath = filePath + '.tmp';
      if (fs.existsSync(tempPath)) fs.unlinkSync(tempPath);
    } catch (e) { }
    return false;
  }
};

/**
 * Vers├гo ass├нncrona do writeJsonFile - n├гo bloqueia o event loop
 * @param {string} filePath - Caminho do arquivo
 * @param {object} data - Dados a serem salvos
 * @returns {Promise<boolean>}
 */
const writeJsonFileAsync = async (filePath, data) => {
  try {
    if (data === undefined || data === null) {
      console.error(`тЭМ writeJsonFileAsync: Tentativa de salvar dados nulos em ${filePath}`);
      return false;
    }

    let jsonString;
    try {
      jsonString = JSON.stringify(data, null, 2);
    } catch (stringifyError) {
      console.error(`тЭМ writeJsonFileAsync: Dados n├гo serializ├бveis para ${filePath}:`, stringifyError.message);
      return false;
    }

    // Valida JSON gerado
    try {
      JSON.parse(jsonString);
    } catch (validateError) {
      console.error(`тЭМ writeJsonFileAsync: JSON inv├бlido gerado para ${filePath}`);
      return false;
    }

    await fsPromises.mkdir(pathz.dirname(filePath), { recursive: true });

    // Escreve em arquivo tempor├бrio primeiro (opera├з├гo at├┤mica)
    const tempPath = filePath + '.tmp';
    await fsPromises.writeFile(tempPath, jsonString, 'utf-8');

    // Verifica integridade
    try {
      const writtenContent = await fsPromises.readFile(tempPath, 'utf-8');
      JSON.parse(writtenContent);
    } catch (verifyError) {
      console.error(`тЭМ writeJsonFileAsync: Verifica├з├гo falhou para ${filePath}`);
      try { await fsPromises.unlink(tempPath); } catch (e) { }
      return false;
    }

    // Move arquivo tempor├бrio para destino (at├┤mico)
    await fsPromises.rename(tempPath, filePath);
    return true;
  } catch (error) {
    console.error(`тЭМ Erro ao escrever JSON async em ${filePath}:`, error.message);
    try {
      const tempPath = filePath + '.tmp';
      await fsPromises.unlink(tempPath).catch(() => { });
    } catch (e) { }
    return false;
  }
};

/**
 * Leitura ass├нncrona de arquivo JSON
 * @param {string} filePath - Caminho do arquivo
 * @param {object} defaultValue - Valor padr├гo se arquivo n├гo existir
 * @returns {Promise<object>}
 */
const readJsonFileAsync = async (filePath, defaultValue = {}) => {
  try {
    const content = await fsPromises.readFile(filePath, 'utf-8');
    return JSON.parse(content);
  } catch (error) {
    if (error.code !== 'ENOENT') {
      console.error(`тЭМ Erro ao ler JSON async de ${filePath}:`, error.message);
    }
    return defaultValue;
  }
};

/**
 * Verifica se arquivo existe (ass├нncrono)
 * @param {string} filePath - Caminho do arquivo
 * @returns {Promise<boolean>}
 */
const fileExistsAsync = async (filePath) => {
  try {
    await fsPromises.access(filePath);
    return true;
  } catch {
    return false;
  }
};




