  // Sistema de degrada├з├гo autom├бtica de pets
  function applyPetDegradation(pets) {
    if (!Array.isArray(pets) || pets.length === 0) return { changed: false };

    const now = Date.now();
    const oneHour = 3600000; // 1 hora em ms
    const oneDayInHours = 24; // Degrada├з├гo total em 24 horas se n├гo cuidar

    let changed = false;

    pets.forEach(pet => {
      // Inicializa lastUpdate se n├гo existir
      if (!pet.lastUpdate) {
        pet.lastUpdate = now;
        changed = true;
        return;
      }

      const timePassed = now - pet.lastUpdate;
      const hoursPassed = timePassed / oneHour;

      // S├│ degrada se passou mais de 1 hora
      if (hoursPassed >= 1) {
        // Calcula degrada├з├гo proporcional ao tempo
        const hungerDegrade = Math.floor(hoursPassed * (100 / oneDayInHours)); // ~4.17 por hora
        const moodDegrade = Math.floor(hoursPassed * (100 / (oneDayInHours * 2))); // ~2.08 por hora (degrada mais devagar)

        // Aplica degrada├з├гo
        const oldHunger = pet.hunger || 100;
        const oldMood = pet.mood || 100;

        pet.hunger = Math.max(0, oldHunger - hungerDegrade);
        pet.mood = Math.max(0, oldMood - moodDegrade);

        // Se fome est├б muito baixa, humor degrada mais r├бpido
        if (pet.hunger < 30) {
          pet.mood = Math.max(0, pet.mood - Math.floor(hoursPassed * 5));
        }

        // Se fome chegou a 0, pet perde HP gradualmente
        if (pet.hunger === 0 && hoursPassed >= 2) {
          const hpLoss = Math.floor(hoursPassed * (pet.maxHp * 0.02)); // 2% do HP m├бximo por hora
          pet.hp = Math.max(1, (pet.hp || pet.maxHp) - hpLoss); // Nunca deixa morrer (m├нnimo 1 HP)
        }

        // Atualiza timestamp
        pet.lastUpdate = now;
        changed = true;
      }
    });

    return { changed };
  }

  // тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР
  // FUN├З├ХES AUXILIARES DO SISTEMA RPG
  // тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР

  // NOTA: PICKAXE_TIER_MULT, fmt, timeLeft, parseAmount, getActivePickaxe e applyShopBonuses
  // s├гo importados de './utils/database.js' (linhas 166-169 e 162-165 dos imports)
  // As declara├з├╡es locais foram removidas para evitar conflito de escopo.

  // Fun├з├гo para remover acentos das palavras (local, n├гo importada)
  function normalizarTexto(texto) {
    return texto.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
  }

  // тХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХРтХР
  // FIM DAS FUN├З├ХES AUXILIARES DO RPG
