        saveEconomy(econ);

        let text = `тХнтФБтФБтФБтК▒ тЪЩя╕П *PROTE├З├ГO ATIVA* тК▒тФБтФБтФБтХо\n`;
        text += `тХ░тФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтХп\n\n`;
