        targetData.reputation.upvotes++;
        targetData.reputation.karma += 5;
        targetData.reputation.fame++;

        me.lastVote[target] = now;

        // ЁЯдЦ EVENTO NPC - VOTO POSITIVO
        await npcManager?.trigger(nazu, from, 'voto_positivo', target, target.split('@')[0]);

        let text = `тХнтФБтФБтФБтК▒ ЁЯСН *VOTO POSITIVO* тК▒тФБтФБтФБтХо\n`;
