        // Normaliza "cara/coroa" com aliases (heads/tails, etc)
        const resolvedChoice = resolveParamAlias(rawChoice);
        const choice = resolvedChoice === 'cara' || resolvedChoice === 'coroa' ? resolvedChoice : null;
        const bet = parseInt(args[1]) || 0;

        if (!choice) {
          return reply(`ЁЯТб Use ${prefix}coinflip <cara|coroa> <valor>\n\nЁЯУЭ Aceita: cara, coroa, heads, tails`);
        }

        if (bet < 100) return reply('ЁЯТ░ Aposta m├нnima: 100 moedas');
        if (me.wallet < bet) return reply('ЁЯТ░ Voc├к n├гo tem moedas suficientes!');

        // Cooldown de 8 minutos
        const cdCoin = me.cooldowns?.coinflip || 0;
        if (Date.now() < cdCoin) return reply(`тП│ Aguarde ${timeLeft(cdCoin)} para jogar novamente.`);

        // COINFLIP NERFADO: 5% de chance de ganhar (era 50%)
        // A moeda ├й "viciada" - quase sempre cai no lado oposto
        const playerWins = Math.random() < 0.05;
        const result = playerWins ? choice : (choice === 'cara' ? 'coroa' : 'cara');

        let text = `тХнтФБтФБтФБтК▒ ЁЯкЩ *COIN FLIP* тК▒тФБтФБтФБтХо\n`;
        text += `тХ░тФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтХп\n\n`;
        text += `ЁЯкЩ Voc├к escolheu: *${choice}*\n`;
        text += `ЁЯкЩ Resultado: *${result}*\n\n`;

        me.cooldowns = me.cooldowns || {};
        me.cooldowns.coinflip = Date.now() + 8 * 60 * 1000; // 8 minutos

        if (choice === result) {
          const win = Math.floor(bet * 1.5); // ganha apenas 1.5x (era 2x)
          me.wallet += win - bet;
          text += `ЁЯОЙ *VIT├УRIA RARA!*\n\n`;
          text += `ЁЯТ░ +${win.toLocaleString()}`;
        } else {
          me.wallet -= bet;
          text += `ЁЯШв *VOC├К PERDEU!*\n\n`;
          text += `ЁЯТ╕ -${bet.toLocaleString()}\nЁЯкЩ A moeda parece viciada...`;
        }

