        if (subCmd === 'ver' || !q) {
          const formatMandate = (m) => {
            const s = String(m);
            if (s.endsWith('m')) return s.replace('m', ' minutos');
            if (s.endsWith('h')) return s.replace('h', ' horas');
            if (s.endsWith('d')) return s.replace('d', ' dias');
            return s + ' dias';
          };

          let text = `тЪЩя╕П *CONFIGURA├З├ХES DA ELEI├З├ГO*\n\n`;
          text += `тП│ *Candidatura:* ${config.candidatura} minutos\n`;
          text += `ЁЯЧ│я╕П *Vota├з├гo:* ${config.votacao} minutos\n`;
          text += `ЁЯММ *Mandato:* ${formatMandate(config.mandato)}\n\n`;
          text += `ЁЯТб *Para alterar, use:*\n`;
          text += `> ${prefix}tempeleicao candidatura <minutos>\n`;
          text += `> ${prefix}tempeleicao votacao <minutos>\n`;
          text += `> ${prefix}tempeleicao mandato <valor><m/h/d>\n`;
          text += `_Ex: !tempeleicao mandato 30m, 12h ou 7d_`;
          return reply(text);
        }

        let msg = '';
        if (subCmd === 'mandato') {
          const rawValue = args[1].toLowerCase();
          if (!/^\d+[mhd]$/.test(rawValue) && !/^\d+$/.test(rawValue)) {
            return reply('тЭМ Formato inv├бlido! Use: 30m, 12h ou 7d.');
          }
          config.mandato = rawValue;
          msg = `тЬЕ Dura├з├гo do mandato definida para ${rawValue}.`;
        } else {
          const value = parseInt(args[1]);
          if (isNaN(value) || value <= 0) return reply('тЭМ Informe um valor num├йrico v├бlido maior que zero.');

          if (subCmd === 'candidatura') {
            config.candidatura = value;
            msg = `тЬЕ Tempo de candidatura definido para ${value} minutos.`;
          } else if (subCmd === 'votacao' || subCmd === 'vota├з├гo') {
            config.votacao = value;
            msg = `тЬЕ Tempo de vota├з├гo definido para ${value} minutos.`;
          } else {
            return reply('тЭМ Subcomando inv├бlido. Use: candidatura, votacao ou mandato.');
          }
        }

        saveElectionConfig(config);
        return reply(msg);
