          for (const [cmdName, cmdData] of Object.entries(cmdStats.commands || {})) {
            for (const [userId, count] of Object.entries(cmdData.users || {})) {
              allUsers.add(userId);
              userCmdCount[userId] = (userCmdCount[userId] || 0) + count;
            }
          }
          const totalUsers = allUsers.size;

          // ==================== GROUPS ====================
          let groups = 0;
